mapper.select:
SELECT r.*
FROM room r
WHERE r.h_code = #{h_code}
  AND r.maxOccupancy >= #{maxOccupancy}
  AND NOT EXISTS (
    SELECT 1
    FROM reservation re
    WHERE re.r_code = r.r_code
      AND re.cancel = 0
      AND re.check_in_date < #{check_out_date}
      AND re.check_out_date > #{check_in_date}
  )
